var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"에드윈….","JPN":"エッドウィン……","ENG":"Edwin...","TWN":"艾德溫……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"5년만에 한다는 변명이 겨우 이거야?","JPN":"5年ぶりに言ったという言い訳が、たったこれだけ？","ENG":"So this is the excuse you came up with after five years?","TWN":"這是你時隔五年，能給出的唯一藉口嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신이 죽은 이유가… 자기가 만든 실험체를 되찾으려다 그런 거라고?","JPN":"あなたは……自分で作った実験体を取り戻そうとして死んだってこと？","ENG":"You died... trying to retrieve a test subject you made?","TWN":"你的死因……是為了找回自己創造的實驗體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하… 하하…","JPN":"ハ……ハハ……","ENG":"Ha... Ha ha...","TWN":"呵呵……呵呵呵呵……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가 어디서 뭘 하고 있든… 당신은 마지막까지 자기 연구에만 매달렸던 거구나.","JPN":"私がどこで何をしていようと……あなたは最後までただ必死に自分の研究をしていたのか。","ENG":"No matter where I am or what I'm doing... all you focused on was your research until the end.","TWN":"無論我在哪，無論我做什麼……直到最後，你的眼裡也只有你的研究。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐지?","JPN":"あれっ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>셰퍼드. 이쪽으로 따라와.</color>","JPN":"<color=#ffd34c>シェパード。こっちに来なさい。</color>","ENG":"<color=#ffd34c>Shepherd. Follow me.</color>","TWN":"<color=#ffd34c>牧羊犬。跟我來。</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"레코더가 멋대로 다른 날짜의 기록을 재생하고 있어.","JPN":"レコーダーが勝手に別の日付の記録を再生している。","ENG":"The recorder started playing a recording of another date on its own.","TWN":"記錄器還在自動播放下一段記錄？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 영상 날짜는…","JPN":"この映像の日付は……","ENG":"The timestamp on this footage is...","TWN":"這個影片的日期是……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…5년 전이라고?","JPN":"……5年前？","ENG":"...from five years ago?","TWN":"……五年前？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"<color=#ffd34c>셰퍼드가 사라졌다! 모든 출입문을 봉쇄해! 프리하트 박사를 찾아!</color>","JPN":"<color=#ffd34c>シェパードが消えた！　すべての出入口を封鎖しろ！　プラハト博士を捜せ！</color>","ENG":"<color=#ffd34c>Shepherd is gone! Close all the entrances! Find Dr. Freeheart!</color>","TWN":"<color=#ffd34c>牧羊犬不見了！封鎖所有出入口！找到普立哈特博士！</color>"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"뾰족한 마음. 점점 가까워져.","JPN":"トゲトゲの心。どんどん近づいてる。","ENG":"Pointy hearts. They're getting closer.","TWN":"毛毛的、刺刺的心。他們正在靠近。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"걱정 마. 무사히 여기서 빠져나갈 테니까.","JPN":"心配するな。無事ここから抜け出せるはずだから。","ENG":"Don't worry. We'll get out of here safely.","TWN":"別擔心。我們會安全離開這裡的。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"왜 어른들은 우릴 해치고 싶어하나요?","JPN":"なんで大人たちはシェパードたちに意地悪するの？","ENG":"Why do adults want to hurt us so bad?","TWN":"為什麼大人要傷害我們？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"우린 아무도 해치지 않았는데.","JPN":"シェパードたちは、誰も悪いことしてないのに。","ENG":"We didn't hurt anyone.","TWN":"我們沒有傷害任何人。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그건 네가 너무 중요한 존재라서 그래.","JPN":"それは、君がとても重要な存在だからだよ。","ENG":"That's because you're very important to them.","TWN":"那是因為你很重要。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"저 사람들은 너에게 셰퍼드란 이름을 지어준 순간부터, 널 소유하고 있다고 생각하거든.","JPN":"あの人たちはシェパードという名前をつけた瞬間から、君のことを所有物だと思ってるんだ。","ENG":"The moment those people named you Shepherd, they thought they could own you.","TWN":"從他們給你命名為牧羊犬的那一刻起，他們就認為你是他們的所有物了。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하지만 누구도 널 소유해선 안 돼. 저 어른들도, 나도, 네 의지를 강제할 순 없어.","JPN":"だけど、誰であっても君を所有してはいけない。あの大人たちも、僕も、君の気持ちを抑えつけることはできないんだよ。","ENG":"Nobody should ever be able to own you. Neither those adults nor I can impose your will.","TWN":"但沒有人能擁有你。無論是我還是那些大人，都無法強迫你的意志。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드의… 의지.","JPN":"シェパードの……気持ち。","ENG":"Shepherd's... will.","TWN":"牧羊犬的……意志。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하지만, 바깥으로 나가는 문이 모두 닫혔어요. 이대로는 못 나갈 거예요.","JPN":"でも、外に出る扉は全部閉ざされちゃった。ここままじゃ出られないよ。","ENG":"But all the doors leading outside are shut. We won't be able to leave.","TWN":"但是，所有通往外面的門都被鎖住了。我們這樣出不去的。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"걱정 마. 곧 보안요원들이 외부로 통하는 차고 문을 열고 진입할 거야.","JPN":"心配するな。警備員が外部に通じる車庫のドアを開けて進入する。","ENG":"Don't worry. Soon, the security agents will open the garage doors leading to the outside and come in here.","TWN":"不用擔心。安全人員很快就會打開通往外面的車庫門。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>실험 도중 러처가 통제를 벗어났다. 섹터 내 보안요원들은 A레벨 경계 프로토콜을 이행할 것.</color>","JPN":"<color=#ffd34c>実験中、ラッチャーが制御不能になった。セクター内の警備員は、レベルA警戒プロトコルを移行するように。</color>","ENG":"<color=#ffd34c>We lost control of Lurcher during an experiment. All security personnel within the sector adhere to the A-level alert protocol.</color>","TWN":"<color=#ffd34c>獵犬在實驗過程中失去了控制。防區內的安全人員，立刻執行A級警報協議！</color>"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그리고 프리하트 박사를 찾아라. 박사가 분명 셰퍼드를 데리고 있을 거다.</color>","JPN":"<color=#ffd34c>そしてプラハト博士を捜せ。きっと博士がシェパードを連れているはずだ。</color>","ENG":"<color=#ffd34c>And find Dr. Freeheart. He must have Shepherd with him.</color>","TWN":"<color=#ffd34c>另外找到普立哈特博士。我確定牧羊犬和他在一起！</color>"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};